async (page) => {
  // Click Village Girl to walk adjacent
  await page.evaluate((label) => window.__clickEntity(label), 'E1');
  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    // Find Village Girl NPC
    const vg = s?.nearby_entities?.find(e => e.name?.includes('Village Girl'));
    return {
      pos: s?.player_position,
      vg_dist: vg?.distance,
      vg_id: vg?.id,
      vg_pos: { x: vg?.x, y: vg?.y }
    };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Try to walk to tile adjacent to Village Girl (136, 146)
  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 137, y: 147});
  await page.waitForTimeout(4000);

  let pos = await page.evaluate(() => window.__latestGameState?.player_position);
  let dist = await page.evaluate(() => {
    const s = window.__latestGameState;
    return s?.nearby_entities?.find(e => e.name?.includes('Village Girl'))?.distance;
  });

  // If still not adjacent, try another tile
  if (dist > 2) {
    await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 136, y: 147});
    await page.waitForTimeout(3000);
    pos = await page.evaluate(() => window.__latestGameState?.player_position);
    dist = await page.evaluate(() => {
      const s = window.__latestGameState;
      return s?.nearby_entities?.find(e => e.name?.includes('Village Girl'))?.distance;
    });
  }

  return JSON.stringify({ pos, dist });
}

async (page) => {
  // Warp to Mudwich
  await page.evaluate(() => {
