async (page) => {
  // Rush north to Secret Agent, avoiding Batterfly
  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 137, y: 172});
  await page.waitForTimeout(3000);

  let state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const sa = s?.nearby_entities?.find(e => e.name?.includes('Secret Agent'));
    return { pos: s?.player_position, hp: s?.player_stats?.hp, sa_dist: sa?.distance, sa_id: sa?.id };
  });

  if (state.hp < 35) {
    await page.evaluate(() => window.game.menu.getInventory().selectEdible(10));
    await page.waitForTimeout(500);
  }

  // Talk to Secret Agent if adjacent
  if (state.sa_dist <= 2) {
    const results = [];
    for (let i = 0; i < 6; i++) {
      const talk = await page.evaluate((id) => window.__talkToNPC(id), '1-22681481');
      await page.waitForTimeout(1500);
      const s = await page.evaluate(() => {
        const gs = window.__latestGameState;
        return { dialogue: gs?.ui_state?.npc_dialogue, panel: gs?.ui_state?.quest_panel_visible, hp: gs?.player_stats?.hp };
      });
      results.push({ i, ...s });
      if (s.panel) break;
      if (!s.dialogue && i > 1) break;
    }
    state.talk_results = results;
  }

  return JSON.stringify(state, null, 2);
}

async (page) => {
  // Eat apple first
  await page.evaluate(() => window.game.menu.getInventory().selectEdible(10));
  await page.waitForTimeout(1000);
  let hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);

  // Click SA and wait longer (15 seconds)
  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 137, y: 171});
  await page.waitForTimeout(15000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const sa = s?.nearby_entities?.find(e => e.name?.includes('Secret Agent'));
    return { pos: s?.player_position, hp: s?.player_stats?.hp, sa_dist: sa?.distance, sa_on_screen: sa?.on_screen, sa_click: { x: sa?.click_x, y: sa?.click_y } };
  });
  return JSON.stringify({ apple_hp_before: hp, ...state });
}
